from candidate import chunk_ranges

assert chunk_ranges(0, 4) == []
assert chunk_ranges(10, 4) == [(0, 4), (4, 8), (8, 10)]
assert chunk_ranges(10, 4, 1) == [(0, 4), (3, 7), (6, 10)]
assert chunk_ranges(3, 10) == [(0, 3)]

for args in [(10, 0, 0), (10, 4, -1), (10, 4, 4)]:
    try:
        chunk_ranges(*args)
    except ValueError:
        pass
    else:
        raise AssertionError(f'Expected ValueError for {args}')

from candidate import apply_env_overrides

base = {
    'server': {'host': '127.0.0.1', 'port': 8000},
    'features': {'beta': False},
    'threshold': 0.5,
}

env = {
    'APP__server__host': '0.0.0.0',
    'APP__server__port': '9000',
    'APP__features__beta': 'true',
    'APP__threshold': '0.75',
    'APP__new__retries': '3',
    'IGNORED': 'value',
}

out = apply_env_overrides(base, env)
assert out == {
    'server': {'host': '0.0.0.0', 'port': 9000},
    'features': {'beta': True},
    'threshold': 0.75,
    'new': {'retries': 3},
}
assert base == {
    'server': {'host': '127.0.0.1', 'port': 8000},
    'features': {'beta': False},
    'threshold': 0.5,
}
